import type { NoiseTexture } from "../dither/types";

export interface NoiseTextureConfig {
  size: number;
  displayName: string;
  dataUrl: string;
}

export const NOISE_TEXTURES: NoiseTextureConfig[] = [
  {
    size: 64,
    displayName: "64×64 (Fast)",
    dataUrl:
      "data:image/png;base64,",
  },
  {
    size: 128,
    displayName: "128×128 (Recommended)",
    dataUrl:
      "data:image/png;base64,",
  },
  {
    size: 256,
    displayName: "256×256 (Highest Quality)",
    dataUrl:
      "data:image/png;base64,",
  },
];

export const DEFAULT_NOISE_TEXTURE = NOISE_TEXTURES[1]; // 128×128

/**
 * Load a noise texture from a data URL
 */
export function loadNoiseTexture(dataUrl: string): Promise<NoiseTexture> {
  return new Promise((resolve, reject) => {
    const img = new Image();
    img.onload = () => {
      const canvas = document.createElement("canvas");
      canvas.width = img.width;
      canvas.height = img.height;
      const ctx = canvas.getContext("2d");

      if (!ctx) {
        reject(new Error("Could not get canvas context"));
        return;
      }

      ctx.drawImage(img, 0, 0);

      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
      const grayscale = new Uint8ClampedArray(canvas.width * canvas.height);

      // Convert to grayscale (already grayscale, just take R channel)
      for (let i = 0; i < imageData.data.length; i += 4) {
        grayscale[i / 4] = imageData.data[i];
      }

      resolve({ data: grayscale, width: canvas.width, height: canvas.height });
    };
    img.onerror = reject;
    img.src = dataUrl;
  });
}
